271 // Try to find any invariant memory reads that will become dereferenceable in
272 // the remainder loop after peeling. The load must also be used (transitively)
273 // by an exit condition. Returns the number of iterations to peel off (at the
274 // moment either 0 or 1).
275 static unsigned peelToTurnInvariantLoadsDerefencebale(Loop &L,
276                                                       DominatorTree &DT,
277                                                       AssumptionCache *AC) {
278   // Skip loops with a single exiting block, because there should be no benefit
279   // for the heuristic below.
280   if (L.getExitingBlock())
281     return 0;
282 
283   // All non-latch exit blocks must have an UnreachableInst terminator.
284   // Otherwise the heuristic below may not be profitable.
285   SmallVector<BasicBlock *, 4> Exits;
286   L.getUniqueNonLatchExitBlocks(Exits);
287   if (any_of(Exits, [](const BasicBlock *BB) {
288         return !isa<UnreachableInst>(BB->getTerminator());
289       }))
290     return 0;
291 
292   // Now look for invariant loads that dominate the latch and are not known to
293   // be dereferenceable. If there are such loads and no writes, they will become
294   // dereferenceable in the loop if the first iteration is peeled off. Also
295   // collect the set of instructions controlled by such loads. Only peel if an
296   // exit condition uses (transitively) such a load.
297   BasicBlock *Header = L.getHeader();
298   BasicBlock *Latch = L.getLoopLatch();
299   SmallPtrSet<Value *, 8> LoadUsers;
300   const DataLayout &DL = L.getHeader()->getDataLayout();
301   for (BasicBlock *BB : L.blocks()) {
302     for (Instruction &I : *BB) {
303       if (I.mayWriteToMemory())
304         return 0;
305 
306       if (LoadUsers.contains(&I))
307         LoadUsers.insert_range(I.users());
308       // Do not look for reads in the header; they can already be hoisted
309       // without peeling.
310       if (BB == Header)
311         continue;
312       if (auto *LI = dyn_cast<LoadInst>(&I)) {
313         Value *Ptr = LI->getPointerOperand();
314         if (DT.dominates(BB, Latch) && L.isLoopInvariant(Ptr) &&
315             !isDereferenceablePointer(Ptr, LI->getType(), DL, LI, AC, &DT))
316           LoadUsers.insert_range(I.users());
317       }
318     }
319   }
320   SmallVector<BasicBlock *> ExitingBlocks;
321   L.getExitingBlocks(ExitingBlocks);
322   if (any_of(ExitingBlocks, [&LoadUsers](BasicBlock *Exiting) {
323         return LoadUsers.contains(Exiting->getTerminator());
324       }))
325     return 1;
326   return 0;
327 }
