329 bool llvm::canPeelLastIteration(const Loop &L, ScalarEvolution &SE) {
330   const SCEV *BTC = SE.getBackedgeTakenCount(&L);
331   Value *Inc;
332   CmpPredicate Pred;
333   BasicBlock *Succ1;
334   BasicBlock *Succ2;
335   // The loop must execute at least 2 iterations to guarantee that peeled
336   // iteration executes.
337   // TODO: Add checks during codegen.
338   if (isa<SCEVCouldNotCompute>(BTC) ||
339       !SE.isKnownPredicate(CmpInst::ICMP_UGT, BTC, SE.getZero(BTC->getType())))
340     return false;
341 
342   // Check if the exit condition of the loop can be adjusted by the peeling
343   // codegen. For now, it must
344   // * exit via the latch,
345   // * the exit condition must be a NE/EQ compare of an induction with step
346   // of 1.
347   BasicBlock *Latch = L.getLoopLatch();
348   return Latch && Latch == L.getExitingBlock() &&
349          match(Latch->getTerminator(),
350                m_Br(m_ICmp(Pred, m_Value(Inc), m_Value()), m_BasicBlock(Succ1),
351                     m_BasicBlock(Succ2))) &&
352          ((Pred == CmpInst::ICMP_EQ && Succ2 == L.getHeader()) ||
353           (Pred == CmpInst::ICMP_NE && Succ1 == L.getHeader())) &&
354          isa<SCEVAddRecExpr>(SE.getSCEV(Inc)) &&
355          cast<SCEVAddRecExpr>(SE.getSCEV(Inc))->getStepRecurrence(SE)->isOne();
356 }
