358 /// Returns true if the last iteration can be peeled off and the condition (Pred
359 /// LeftAR, RightSCEV) is known at the last iteration and the inverse condition
360 /// is known at the second-to-last.
361 static bool shouldPeelLastIteration(Loop &L, CmpPredicate Pred,
362                                     const SCEVAddRecExpr *LeftAR,
363                                     const SCEV *RightSCEV,
364                                     ScalarEvolution &SE) {
365   if (!canPeelLastIteration(L, SE))
366     return false;
367 
368   const SCEV *BTC = SE.getBackedgeTakenCount(&L);
369   const SCEV *ValAtLastIter = LeftAR->evaluateAtIteration(BTC, SE);
370   const SCEV *ValAtSecondToLastIter = LeftAR->evaluateAtIteration(
371       SE.getMinusSCEV(BTC, SE.getOne(BTC->getType())), SE);
372 
373   return SE.isKnownPredicate(ICmpInst::getInversePredicate(Pred), ValAtLastIter,
374                              RightSCEV) &&
375          SE.isKnownPredicate(Pred, ValAtSecondToLastIter, RightSCEV);
376 }
